import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import response from './response.json';

interface LoyaltyData {
  balance: {
    currentPoints: number;
    tier: string;
  };
  recentTransactions: {
    date: string;
    description: string;
    points: number;
  }[];
  availableRewards: {
    reward: string;
    pointsRequired: number;
  }[];
}

export default function Widget() {
  const { balance, recentTransactions, availableRewards } = response.data as LoyaltyData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Loyalty Points
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {balance.currentPoints.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Tier: {balance.tier}
            </Typography>
          </Box>

          <Divider />

          <Box>
            <Typography variant="body1" fontWeight={500} sx={{ mb: 1 }}>
              Recent Transactions
            </Typography>
            <Stack spacing={1}>
              {recentTransactions.slice(0, 3).map((transaction, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ color: '#374151' }}>
                    {transaction.description}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {transaction.date} - {transaction.points} points
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <Divider />

          <Box>
            <Typography variant="body1" fontWeight={500} sx={{ mb: 1 }}>
              Available Rewards
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {availableRewards.map((reward, index) => (
                <Chip
                  key={index}
                  label={`${reward.reward} (${reward.pointsRequired} pts)`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
